function advantageCount(nums1, nums2) {
    const sortedNums1 = [...nums1].sort((a, b) => a - b);
    const result = [];
    for (const num of nums2) {
        let index = sortedNums1.findIndex(el => el > num);
        if (index === -1) index = 0;
        result.push(sortedNums1[index]);
        sortedNums1.splice(index, 1);
    }
    return result;
}
```

