    ```java
import java.util.*;

class Solution {
    public int[] advantageCount(int[] nums1, int[] nums2) {
        int n = nums1.length;
        int[] result = new int[n];
        TreeSet<Integer> set = new TreeSet<>();
        for (int num : nums1) set.add(num);
        for (int i = 0; i < n; i++) {
            Integer greater = set.higher(nums2[i]);
            if (greater == null) {
                greater = set.first();
            }
            set.remove(greater);
            result[i] = greater;
        }
        return result;
    }
}
```

